bool List_ser(FILE *out, List<Index> x) {
  u64 count = 0;
  for (List<Index> node = x; node; node = node->next) count++;
  if (!cbor_encode_array_start(out, count)) return false;
  for (List<Index> node = x; node; node = node->next)
    if (!Index_ser(out, node->index)) return false;
return true;
}

