bool List_des(FILE *in, struct region *region, List<Index>* x) {
u64 count = 0;
    if (!cbor_decode_array_start(in, &count)) return false;
    List<Index> current = *x = NULL;
    for (; count > 0; count--) {
      List<Index> node = static_cast<List<Index>>(region_alloc(region, sizeof(*node)));
      node->next = NULL;
      if (!current) {
        *x = current = node;
      } else {
        current->next = node;
        current = node;
      }
      if (!Index_des(in, region, &node->index)) return false;
    }
return true;
}

