bool KLRFile_ser(FILE *out, Ptr<KLRFile> x) {
if (!cbor_encode_tag(out, 217, 247, 3)) return false;
if (!cbor_encode_uint(out, x->major)) return false;
if (!cbor_encode_uint(out, x->minor)) return false;
if (!cbor_encode_uint(out, x->patch)) return false;
return true;
}

bool KLRMetaData_ser(FILE *out, Ptr<KLRMetaData> x) {
if (!cbor_encode_tag(out, 235, 0, 1)) return false;
if (!String_ser(out, x->format)) return false;
return true;
}

bool Contents_ser(FILE *out, Ptr<Contents> x) {
switch (x->tag) {
case Contents_python:
if (!cbor_encode_tag(out, 236, 0, 1)) return false;
if (!Kernel_ser(out, x->python.kernel)) return false;
break;
case Contents_nki:
if (!cbor_encode_tag(out, 236, 1, 1)) return false;
if (!Kernel_ser(out, x->nki.kernel)) return false;
break;
case Contents_klir:
if (!cbor_encode_tag(out, 236, 2, 1)) return false;
if (!Kernel_ser(out, x->klir.kernel)) return false;
break;
case Contents_hlo:
if (!cbor_encode_tag(out, 236, 3, 1)) return false;
if (!String_ser(out, x->hlo.name)) return false;
break;
default: return false;
}
return true;
}


